#include <iostream>
#include <queue>
#include <vector>
using namespace std;

// Structure to represent a graph
struct Graph {
    int numVertices;
    vector<vector<int>> adjList;
};

// Function to create a graph
Graph createGraph(int numVertices) {
    Graph graph;
    graph.numVertices = numVertices;
    graph.adjList.resize(numVertices);
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph& graph, int src, int dest) {
    graph.adjList[src].push_back(dest);
    graph.adjList[dest].push_back(src);
}

// Function to perform BFS traversal
void bfsTraversal(Graph& graph, int startVertex) {
    vector<bool> visited(graph.numVertices, false);
    queue<int> q;
    q.push(startVertex);
    visited[startVertex] = true;
    while (!q.empty()) {
        int currentVertex = q.front();
        cout << currentVertex + 1 << " ";
        q.pop();
        for (int neighbor : graph.adjList[currentVertex]) {
            if (!visited[neighbor]) {
                q.push(neighbor);
                visited[neighbor] = true;
            }
        }
    }
    cout << endl;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int t;
    cin >> t;
    while (t--) {
        int numVertices, numEdges;
        cin >> numVertices >> numEdges;
        Graph graph = createGraph(numVertices);
        for (int i = 0; i < numEdges; i++) {
            int src, dest;
            cin >> src >> dest;
            addEdge(graph, src - 1, dest - 1);
        }
        cout << "BFS traversal: ";
        bfsTraversal(graph, 0);
    }
    return 0;
}

